//ascii排序
function sort_ASCII(obj) {

	var arr = new Array();
	var num = 0;
	for (var i in obj) {
		arr[num] = i;
		num++;
	}
	var sortArr = arr.sort();
	var sortObj = {};
	for (var i in sortArr) {
		if (sortArr[i] != 'rule_key') {
			sortObj[sortArr[i]] = obj[sortArr[i]];
		}
	}
	return sortObj;
}
//对象转为字符串
function data_toStirng(obj) {
	let str = ''
	let arrayData = []
	Object.getOwnPropertyNames(obj).forEach(function(key) {
		if (obj[key]) {
			arrayData.push(key + '=' + obj[key]);
		}
	})
	for (let i = 0; i < arrayData.length; i++) {
		//最后一条数据
		let lastLength = arrayData.length - 1;
		//如果不是最后一条数据加上& 
		if (i !== lastLength) {
			str += arrayData[i] + '&'
		} else {
			str += arrayData[lastLength]
		}
	}
	return str;

}
//获取rule_key
function rule_key(data) {
	let asciiData = sort_ASCII(data);
	let asciiData_toStirng = data_toStirng(asciiData);
	let md5data = md5(asciiData_toStirng);
	let upperCaseData = md5data.toUpperCase();
	return upperCaseData;
}

requests.post = (url, data) => {
	var loginToken = '7af5c9adaff25ddd0ec5da820cc8a831349b25e6';
	// var loginToken = 'a4ac2cc8dd96c48572d0ed241ea7fa5e471b86b9';

	// var loginToken = ''
	// uni.getStorage({
	//     key: 'Login_token',
	//     success: function (res) {
	// 		loginToken = res.data;
	//     }
	// });
	var objData = data;
	let timestamp = (Date.parse(new Date())) / 1000;
	//公用loginToken
	if (loginToken) {
		var publicData = {
			scope: store.state.scope,
			timestamp: timestamp,
			login_token: loginToken
		};
	} else {
		var publicData = {
			scope: store.state.scope,
			timestamp: timestamp
		};
	}
	objData = Object.assign(data, publicData);
	var ruleKey = rule_key(objData);
	objData = Object.assign(data, {
		rule_key: ruleKey
	});
	
	let promise = new Promise(function(resolve, reject) {
		uni.request({
			url: baseUrl + url,
			data: objData,
			method: "POST",
			header: {},
			success(res) {
				// if(res.data.code == 1000){
				resolve(res.data)
				// }
				uni.hideLoading();
				successState(res)

			},
			fail(err) {
				uni.hideLoading();
				// errorState(err)
				reject(err)
			}
		});
	})
	return promise
}

export default requests;
